package forecast

import (
	"math"
	"testing"
	"time"
)

// makeSeries creates a test series of n daily points starting from a base time,
// with values generated by the given function.
func makeSeries(n int, fn func(i int) float64) Series {
	base := time.Date(2026, 1, 1, 0, 0, 0, 0, time.UTC)
	s := make(Series, n)
	for i := 0; i < n; i++ {
		s[i] = Point{
			T: base.AddDate(0, 0, i),
			V: fn(i),
		}
	}
	return s
}

func TestRun_MinimumDataPoints(t *testing.T) {
	s := makeSeries(2, func(i int) float64 { return float64(i) })
	_, err := Run(s, Config{Method: MethodLinear, Horizon: 3})
	if err == nil {
		t.Fatal("expected error for < 3 data points")
	}
}

func TestRun_LinearTrend(t *testing.T) {
	// y = 10 + 5*x — clear upward trend.
	s := makeSeries(30, func(i int) float64 { return 10 + 5*float64(i) })

	result, err := Run(s, Config{
		Method:   MethodLinear,
		Horizon:  5,
		Interval: IntervalDay,
		Metric:   "total_income",
	})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	if result.Method != MethodLinear {
		t.Errorf("method = %q, want %q", result.Method, MethodLinear)
	}
	if result.Metric != "total_income" {
		t.Errorf("metric = %q, want %q", result.Metric, "total_income")
	}
	if len(result.Predictions) != 5 {
		t.Fatalf("got %d predictions, want 5", len(result.Predictions))
	}
	if result.DataPoints != 30 {
		t.Errorf("data_points = %d, want 30", result.DataPoints)
	}

	// With a perfect linear series, the slope should be exactly 5.
	if math.Abs(result.Trend-5.0) > 0.01 {
		t.Errorf("trend = %.4f, want ~5.0", result.Trend)
	}

	// First prediction should be ~10 + 5*30 = 160.
	expected := 10 + 5.0*30
	if math.Abs(result.Predictions[0].Value-expected) > 0.1 {
		t.Errorf("first prediction = %.2f, want ~%.2f", result.Predictions[0].Value, expected)
	}

	// Bounds should be present and ordered.
	for i, p := range result.Predictions {
		if p.LowerBound > p.Value {
			t.Errorf("prediction[%d]: lower_bound (%.2f) > value (%.2f)", i, p.LowerBound, p.Value)
		}
		if p.UpperBound < p.Value {
			t.Errorf("prediction[%d]: upper_bound (%.2f) < value (%.2f)", i, p.UpperBound, p.Value)
		}
	}
}

func TestRun_LinearFlat(t *testing.T) {
	// Flat series — should predict the same constant value.
	s := makeSeries(20, func(i int) float64 { return 42.0 })

	result, err := Run(s, Config{Method: MethodLinear, Horizon: 3})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	for _, p := range result.Predictions {
		if math.Abs(p.Value-42.0) > 0.01 {
			t.Errorf("flat prediction = %.4f, want 42.0", p.Value)
		}
	}
	if math.Abs(result.Trend) > 0.01 {
		t.Errorf("trend = %.4f, want ~0", result.Trend)
	}
}

func TestRun_SMA(t *testing.T) {
	// Last 5 values average to (10+11+12+13+14)/5 = 12.
	s := makeSeries(15, func(i int) float64 { return float64(i) })

	result, err := Run(s, Config{
		Method:    MethodSMA,
		Horizon:   3,
		Interval:  IntervalDay,
		SMAWindow: 5,
	})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	if result.Method != MethodSMA {
		t.Errorf("method = %q, want %q", result.Method, MethodSMA)
	}

	// SMA of last 5 points: (10+11+12+13+14)/5 = 12.
	expectedAvg := 12.0
	for _, p := range result.Predictions {
		if math.Abs(p.Value-expectedAvg) > 0.01 {
			t.Errorf("SMA prediction = %.4f, want ~%.1f", p.Value, expectedAvg)
		}
	}
}

func TestRun_WMA(t *testing.T) {
	// WMA with window=3 on [10, 20, 30]:
	// (10*1 + 20*2 + 30*3) / (1+2+3) = (10+40+90)/6 = 140/6 ≈ 23.33.
	s := makeSeries(3, func(i int) float64 { return float64((i + 1) * 10) })

	result, err := Run(s, Config{
		Method:    MethodWMA,
		Horizon:   2,
		Interval:  IntervalDay,
		SMAWindow: 3,
	})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	expected := 140.0 / 6.0
	for _, p := range result.Predictions {
		if math.Abs(p.Value-expected) > 0.1 {
			t.Errorf("WMA prediction = %.4f, want ~%.2f", p.Value, expected)
		}
	}
}

func TestRun_HoltWinters(t *testing.T) {
	// Linear trend with noise — Holt-Winters should capture the upward trend.
	s := makeSeries(30, func(i int) float64 {
		// Base trend + small oscillation.
		return 100 + 3*float64(i) + 2*math.Sin(float64(i)*0.5)
	})

	result, err := Run(s, Config{
		Method:   MethodHoltWinters,
		Horizon:  5,
		Interval: IntervalDay,
	})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	if result.Method != MethodHoltWinters {
		t.Errorf("method = %q, want %q", result.Method, MethodHoltWinters)
	}

	// Predictions should be in the 190+ range (100 + 3*30 = 190 baseline).
	for _, p := range result.Predictions {
		if p.Value < 150 || p.Value > 250 {
			t.Errorf("HoltWinters prediction %.2f out of expected range [150, 250]", p.Value)
		}
	}

	// Trend should be positive (roughly 3).
	if result.Trend <= 0 {
		t.Errorf("expected positive trend, got %.4f", result.Trend)
	}
}

func TestRun_Auto(t *testing.T) {
	s := makeSeries(30, func(i int) float64 { return 50 + 2*float64(i) })

	result, err := Run(s, Config{
		Method:   MethodAuto,
		Horizon:  5,
		Interval: IntervalDay,
	})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	// Auto should pick a method and produce valid predictions.
	if result.Method == MethodAuto {
		t.Error("auto should resolve to a concrete method")
	}
	if len(result.Predictions) != 5 {
		t.Errorf("got %d predictions, want 5", len(result.Predictions))
	}
}

func TestRun_BoundsWiden(t *testing.T) {
	// Bounds should widen as we forecast further out.
	s := makeSeries(30, func(i int) float64 { return 100 + float64(i) + 5*math.Sin(float64(i)) })

	result, err := Run(s, Config{
		Method:   MethodLinear,
		Horizon:  10,
		Interval: IntervalDay,
	})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	firstSpread := result.Predictions[0].UpperBound - result.Predictions[0].LowerBound
	lastSpread := result.Predictions[9].UpperBound - result.Predictions[9].LowerBound

	if lastSpread <= firstSpread {
		t.Errorf("bounds should widen: first spread=%.2f, last spread=%.2f", firstSpread, lastSpread)
	}
}

func TestRun_TimeProgression(t *testing.T) {
	s := makeSeries(10, func(i int) float64 { return float64(i) })

	result, err := Run(s, Config{
		Method:   MethodLinear,
		Horizon:  3,
		Interval: IntervalDay,
	})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	lastData := s[len(s)-1].T
	for i, p := range result.Predictions {
		expected := lastData.AddDate(0, 0, i+1)
		if !p.T.Equal(expected) {
			t.Errorf("prediction[%d] time = %v, want %v", i, p.T, expected)
		}
	}
}

func TestRun_WeekInterval(t *testing.T) {
	base := time.Date(2026, 1, 5, 0, 0, 0, 0, time.UTC) // Monday
	s := make(Series, 10)
	for i := 0; i < 10; i++ {
		s[i] = Point{T: base.AddDate(0, 0, i*7), V: float64(i * 100)}
	}

	result, err := Run(s, Config{
		Method:   MethodLinear,
		Horizon:  3,
		Interval: IntervalWeek,
	})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	lastData := s[len(s)-1].T
	for i, p := range result.Predictions {
		expected := lastData.AddDate(0, 0, (i+1)*7)
		if !p.T.Equal(expected) {
			t.Errorf("prediction[%d] time = %v, want %v", i, p.T, expected)
		}
	}
}

