func TestRun_TrendPercentage(t *testing.T) {
	// y = 100 + 10*x, mean ≈ 245, slope = 10, trend_pct ≈ 10/245 * 100 ≈ 4.08%.
	s := makeSeries(30, func(i int) float64 { return 100 + 10*float64(i) })

	result, err := Run(s, Config{Method: MethodLinear, Horizon: 1})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	if result.TrendPct <= 0 {
		t.Errorf("expected positive trend_pct, got %.4f", result.TrendPct)
	}
}

func TestRun_SeasonalWeights(t *testing.T) {
	s := makeSeries(14, func(i int) float64 { return 100 })

	weights := SeasonalWeights{
		time.Monday:  1.5,
		time.Tuesday: 0.8,
	}

	result, err := Run(s, Config{
		Method:          MethodSMA,
		Horizon:         7,
		Interval:        IntervalDay,
		SeasonalWeights: weights,
	})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	// Find which predictions fall on Monday/Tuesday and verify they were adjusted.
	for _, p := range result.Predictions {
		dow := p.T.Weekday()
		if dow == time.Monday && math.Abs(p.Value-150) > 5 {
			t.Errorf("Monday prediction = %.2f, expected ~150 (100 * 1.5)", p.Value)
		}
		if dow == time.Tuesday && math.Abs(p.Value-80) > 5 {
			t.Errorf("Tuesday prediction = %.2f, expected ~80 (100 * 0.8)", p.Value)
		}
	}
}

func TestRun_DefaultConfig(t *testing.T) {
	s := makeSeries(30, func(i int) float64 { return float64(i * 10) })

	result, err := Run(s, Config{})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	// Defaults: horizon=7, interval=day, method=auto, confidence=0.95.
	if result.Horizon != 7 {
		t.Errorf("default horizon = %d, want 7", result.Horizon)
	}
	if result.Interval != IntervalDay {
		t.Errorf("default interval = %q, want %q", result.Interval, IntervalDay)
	}
	if len(result.Predictions) != 7 {
		t.Errorf("got %d predictions, want 7", len(result.Predictions))
	}
}

func TestBacktest_ProducesMetrics(t *testing.T) {
	s := makeSeries(30, func(i int) float64 { return 50 + 2*float64(i) + 3*math.Sin(float64(i)) })

	result, err := Run(s, Config{Method: MethodLinear, Horizon: 5})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	if result.MAE < 0 {
		t.Errorf("MAE should be non-negative, got %.4f", result.MAE)
	}
	if result.RMSE < 0 {
		t.Errorf("RMSE should be non-negative, got %.4f", result.RMSE)
	}
	if result.RMSE < result.MAE {
		t.Errorf("RMSE (%.4f) should be >= MAE (%.4f)", result.RMSE, result.MAE)
	}
}

func TestSeriesMean(t *testing.T) {
	s := Series{{V: 10}, {V: 20}, {V: 30}}
	got := seriesMean(s)
	if math.Abs(got-20.0) > 0.001 {
		t.Errorf("seriesMean = %.2f, want 20.0", got)
	}
}

func TestSeriesStdDev(t *testing.T) {
	s := Series{{V: 10}, {V: 20}, {V: 30}}
	got := seriesStdDev(s)
	// Population stddev of [10,20,30] = sqrt(200/3) ≈ 8.165.
	expected := math.Sqrt(200.0 / 3.0)
	if math.Abs(got-expected) > 0.01 {
		t.Errorf("seriesStdDev = %.4f, want ~%.4f", got, expected)
	}
}

func TestZScore(t *testing.T) {
	tests := []struct {
		conf     float64
		expected float64
	}{
		{0.99, 2.576},
		{0.95, 1.960},
		{0.90, 1.645},
		{0.80, 1.282},
		{0.50, 1.960}, // fallback
	}
	for _, tc := range tests {
		got := zScore(tc.conf)
		if got != tc.expected {
			t.Errorf("zScore(%.2f) = %.3f, want %.3f", tc.conf, got, tc.expected)
		}
	}
}

